"""GateDataset — loads labeled frames generated by scripts/gen_dataset.py.

Label file format (labels.jsonl): one JSON object per line:
  {
    "file":          "images/frame_000000.jpg",
    "gate_detected": true,
    "cx":            0.52,    # gate center x, normalized [0, 1]
    "cy":            0.48,    # gate center y, normalized [0, 1]
    "bw":            0.14,    # bbox width, normalized [0, 1]
    "bh":            0.18,    # bbox height, normalized [0, 1]
    "area":          43008.0, # bounding box area in original-res pixels
    "scale":         0.21     # mock sim gate scale at capture time
  }

Usage:
    ds = GateDataset("data/gate_dataset", input_h=128, input_w=160, augment=True)
    loader = DataLoader(ds, batch_size=64, shuffle=True, num_workers=4)
    images, labels = next(iter(loader))
    # images: (B, 3, H, W) float32 in [0, 1]
    # labels: (B, 5) float32 — [det, cx, cy, bw, bh]
"""
from __future__ import annotations

import json
import os
from pathlib import Path
from typing import Optional

import cv2
import numpy as np
import torch
from torch.utils.data import Dataset


class GateDataset(Dataset):
    """PyTorch Dataset for gate detection frames.

    Args:
        root:     Path to dataset root (contains images/ and labels.jsonl).
        input_h:  Resize height for model input.
        input_w:  Resize width for model input.
        augment:  If True, apply random photometric augmentation.
        split:    "all" | "train" | "val" — val is last 15% of data.
    """

    def __init__(
        self,
        root: str | Path,
        input_h: int = 128,
        input_w: int = 160,
        augment: bool = False,
        split: str = "all",
    ):
        self.root = Path(root)
        self.input_h = input_h
        self.input_w = input_w
        self.augment = augment

        labels_path = self.root / "labels.jsonl"
        if not labels_path.exists():
            raise FileNotFoundError(f"labels.jsonl not found in {root}")

        with open(labels_path) as f:
            all_rows = [json.loads(line) for line in f if line.strip()]

        # Deterministic split: last 15% → val
        n_val = max(1, int(len(all_rows) * 0.15))
        if split == "train":
            self.rows = all_rows[:-n_val]
        elif split == "val":
            self.rows = all_rows[-n_val:]
        else:
            self.rows = all_rows

        self._rng = np.random.default_rng(0)

        # Cache all images in RAM — eliminates disk I/O after first load.
        # 75K images at 128×160×3 uint8 ≈ 4.6 GB. Use cache=True only if RAM allows.
        # With resize to model input size first, each image is 128×160×3 = 61 KB → ~4.6 GB total.
        # Default: cache resized images (much smaller than originals).
        print(f"  Loading {len(self.rows)} images into RAM...", end=" ", flush=True)
        self._cache: list = [None] * len(self.rows)
        for i, row in enumerate(self.rows):
            img_path = self.root / row["file"]
            img_bgr = cv2.imread(str(img_path))
            if img_bgr is None:
                img_bgr = np.zeros((self.input_h, self.input_w, 3), dtype=np.uint8)
            img_rgb = cv2.cvtColor(img_bgr, cv2.COLOR_BGR2RGB)
            self._cache[i] = cv2.resize(img_rgb, (self.input_w, self.input_h))
        print("done.", flush=True)

    def __len__(self) -> int:
        return len(self.rows)

    def __getitem__(self, idx: int) -> tuple[torch.Tensor, torch.Tensor]:
        row = self.rows[idx]
        img_path = self.root / row["file"]

        img_rgb = self._cache[idx]

        # Optional photometric augmentation (training only)
        if self.augment:
            img_rgb = self._augment(img_rgb)

        # (H, W, 3) uint8 → (3, H, W) float32 in [0, 1]
        tensor = torch.from_numpy(img_rgb).permute(2, 0, 1).float() / 255.0

        # Label: [det, cx, cy, bw, bh]
        det = 1.0 if row["gate_detected"] else 0.0
        if row["gate_detected"]:
            label = torch.tensor(
                [det, row["cx"], row["cy"], row["bw"], row["bh"]], dtype=torch.float32
            )
        else:
            label = torch.tensor([0.0, 0.5, 0.5, 0.0, 0.0], dtype=torch.float32)

        return tensor, label

    # ------------------------------------------------------------------
    # Augmentation
    # ------------------------------------------------------------------

    def _augment(self, img: np.ndarray) -> np.ndarray:
        """Light photometric augmentation (no geometric — preserves labels)."""
        rng = self._rng

        # Brightness + contrast
        if rng.random() < 0.7:
            alpha = float(rng.uniform(0.6, 1.4))   # contrast
            beta  = float(rng.uniform(-40, 40))     # brightness
            img = np.clip(img.astype(np.float32) * alpha + beta, 0, 255).astype(np.uint8)

        # Gaussian noise
        if rng.random() < 0.5:
            std = float(rng.uniform(3, 20))
            noise = rng.normal(0, std, img.shape)
            img = np.clip(img.astype(np.float32) + noise, 0, 255).astype(np.uint8)

        # Gamma
        if rng.random() < 0.4:
            g = float(rng.uniform(0.5, 2.0))
            table = np.array([(i / 255.0) ** (1.0 / g) * 255
                               for i in range(256)], dtype=np.uint8)
            img = cv2.LUT(img, table)

        # Horizontal flip (gate bbox is symmetric so labels stay valid for cx only
        # if we also flip cx → 1 - cx; skip flip to keep things simple)

        return img


# ---------------------------------------------------------------------------
# Stats helper
# ---------------------------------------------------------------------------

def dataset_stats(root: str | Path) -> dict:
    """Return quick stats about a dataset folder."""
    root = Path(root)
    labels_path = root / "labels.jsonl"
    with open(labels_path) as f:
        rows = [json.loads(line) for line in f if line.strip()]

    n_total = len(rows)
    n_pos = sum(1 for r in rows if r["gate_detected"])
    n_neg = n_total - n_pos
    return {
        "total": n_total,
        "positive": n_pos,
        "negative": n_neg,
        "pos_frac": n_pos / max(n_total, 1),
    }
